    message: Option<String>,
    critical: bool,
}

impl DoctorResult {
    fn from_checks(checks: Vec<DoctorCheck>) -> Self {
        let passed = checks.iter().filter(|c| c.critical).all(|c| c.passed);
        Self { passed, checks }
    }
}

/// TruthfulBidir connector state.
#[derive(Debug)]
pub struct TruthfulBidirConnector {
    base: BaseConnector,
