impl TruthfulBidirConnector {
    /// Create a new connector instance.
    pub fn new() -> Self {
        Self {
            base: BaseConnector::new(ConnectorId::from_static("fcp.truthful-bidir")),
            configured: false,
            config: None,
            runtime: None,
            retry_config: HttpRetryConfig::default(),
            stream: Mutex::new(StreamSupervisor::new()),
            started_at: Instant::now(),
            verifier: None,
        }
    }

    fn manifest_hash() -> String {
        let mut hasher = Sha256::new();
        hasher.update(MANIFEST_TOML.as_bytes());
        format!("sha256:{}", hex::encode(hasher.finalize()))
    }

    fn enforce_limits(&self, input: &serde_json::Value) -> FcpResult<()> {{
        if limits::MAX_MESSAGE_CHARS > 0 {{
            if let Some(message) = input.get("message").and_then(|value| value.as_str()) {{
                if message.chars().count() > limits::MAX_MESSAGE_CHARS {{
                    return Err(FcpError::InvalidRequest {{
                        code: 1005,
                        message: "message exceeds MAX_MESSAGE_CHARS limit".to_string(),
                    }});
                }}
            }}
        }}
        if limits::MAX_PAYLOAD_BYTES > 0 && input.to_string().len() > limits::MAX_PAYLOAD_BYTES {{
            return Err(FcpError::InvalidRequest {{
                code: 1006,
                message: "payload exceeds MAX_PAYLOAD_BYTES limit".to_string(),
            }});
        }}
        Ok(())
    }}

    fn scaffold_next_steps() -> Vec<String> {
        vec![
            "Replace scaffold_status with the smallest real provider-backed slice you can verify.".to_string(),
            "Add only the capabilities and network constraints required for that slice.".to_string(),
            "Keep manifest status, runtime truth, and evidence aligned before advertising live support.".to_string(),
        ]
    }

    fn scaffold_status_payload(&self, include_next_steps: bool) -> serde_json::Value {
        let mut payload = json!({
            "connector_id": self.id().as_str(),
            "manifest_status": SURFACE_STATUS,
            "surface_status": SURFACE_STATUS,
            "live_requests_supported": false,
            "implemented_operations": [OP_SCAFFOLD_STATUS],
        });
        if include_next_steps {
            payload
                .as_object_mut()
                .expect("scaffold status payload should be an object")
                .insert("next_steps".into(), json!(Self::scaffold_next_steps()));
        }
        payload
    }

    fn scaffold_status_operation(&self) -> OperationInfo {
        OperationInfo {
            id: OperationId::from_static(OP_SCAFFOLD_STATUS),
            summary: "Inspect scaffold status".to_string(),
            description: Some(
                "Reports the connector's incubating scaffold status and graduation checklist."
                    .to_string(),
            ),
            input_schema: serde_json::json!({
                "type": "object",
                "properties": {
                    "include_next_steps": { "type": "boolean" }
                }
            }),
            output_schema: serde_json::json!({
                "type": "object",
                "properties": {
                    "connector_id": { "type": "string" },
                    "manifest_status": { "type": "string" },
                    "surface_status": { "type": "string" },
                    "live_requests_supported": { "type": "boolean" },
                    "implemented_operations": {
                        "type": "array",
                        "items": { "type": "string" }
                    },
                    "next_steps": {
                        "type": "array",
                        "items": { "type": "string" }
                    }
                },
                "required": [
                    "connector_id",
                    "manifest_status",
                    "surface_status",
                    "live_requests_supported",
                    "implemented_operations"
                ]
            }),
            capability: CapabilityId::from_static(CAP_SCAFFOLD_STATUS),
            risk_level: RiskLevel::Low,
            safety_tier: SafetyTier::Safe,
            idempotency: IdempotencyClass::BestEffort,
            ai_hints: AgentHint {
                when_to_use:
                    "Use this operation to confirm the generated connector is still incubating and non-live."
                        .to_string(),
                common_mistakes: vec![
                    "Treating the scaffold status payload as proof of live upstream support"
                        .to_string(),
                    "Advertising capabilities before the matching provider-backed invoke path exists"
                        .to_string(),
                ],
                examples: Vec::new(),
                related: Vec::new(),
            },
            rate_limit: None,
            requires_approval: Some(ApprovalMode::None),
        }
    }

    /// Run connector diagnostics (V3 doctor endpoint).
    ///
    /// Returns a structured readiness report without leaking secrets.
    pub fn doctor(&self) -> DoctorResult {
        let mut checks = Vec::new();

        // Check 1: Configuration loaded
        let configured = self.config.is_some();
        checks.push(DoctorCheck {
            name: "configuration".into(),
            passed: configured,
            message: Some(if configured {
                "Configuration loaded".into()
            } else {
                "Not configured - run configure first".into()
            }),
            critical: true,
        });

        // Check 2: Runtime initialized
        let runtime_ok = self.runtime.is_some();
        checks.push(DoctorCheck {
            name: "runtime".into(),
            passed: runtime_ok,
            message: Some(if runtime_ok {
                "ConnectorRuntime initialized".into()
            } else {
                "Runtime missing; re-run configure".into()
            }),
            critical: true,
        });

        // Check 3: Capability verifier
        let verifier_ok = self.verifier.is_some();
        checks.push(DoctorCheck {
            name: "capability_verifier".into(),
            passed: verifier_ok,
            message: Some(if verifier_ok {
                "Capability verifier initialized".into()
            } else {
                "Verifier missing; run handshake first".into()
            }),
            critical: false,
        });

        checks.push(DoctorCheck {
            name: "surface_status".into(),
            passed: false,
            message: Some(
                "Connector remains incubating; only the local scaffold_status operation is implemented".into(),
            ),
            critical: false,
        });

        DoctorResult::from_checks(checks)
    }
}

