const MANIFEST_TOML: &str = include_str!("../manifest.toml");
const SURFACE_STATUS: &str = "incubating";
const OP_SCAFFOLD_STATUS: &str = "truthful-poll.scaffold_status";
const CAP_SCAFFOLD_STATUS: &str = "truthful-poll.scaffold_status";
const SUPPORTS_STREAMING: bool = false;

// ─────────────────────────────────────────────────────────────────────────────
// Doctor types (connector-local diagnostics)
// ─────────────────────────────────────────────────────────────────────────────

/// Result of a connector doctor check.
#[derive(Debug, Clone, serde::Serialize)]
struct DoctorResult {
    passed: bool,
    checks: Vec<DoctorCheck>,
}

/// A single diagnostic check within a doctor run.
#[derive(Debug, Clone, serde::Serialize)]
struct DoctorCheck {
    name: String,
    passed: bool,
    message: Option<String>,
    critical: bool,
}

impl DoctorResult {
    fn from_checks(checks: Vec<DoctorCheck>) -> Self {
        let passed = checks.iter().filter(|c| c.critical).all(|c| c.passed);
        Self { passed, checks }
    }
}

/// TruthfulPoll connector state.
#[derive(Debug)]
pub struct TruthfulPollConnector {
    base: BaseConnector,
    configured: bool,
    config: Option<TruthfulPollConfig>,
    runtime: Option<ConnectorRuntime>,
    retry_config: HttpRetryConfig,
    polling: Mutex<PollingSupervisor>,
    started_at: Instant,
    verifier: Option<CapabilityVerifier>,
}

impl TruthfulPollConnector {
    /// Create a new connector instance.
    pub fn new() -> Self {
        Self {
            base: BaseConnector::new(ConnectorId::from_static("fcp.truthful-poll")),
            configured: false,
            config: None,
            runtime: None,
            retry_config: HttpRetryConfig::default(),
            polling: Mutex::new(PollingSupervisor::new()),
            started_at: Instant::now(),
            verifier: None,
        }
    }

    fn manifest_hash() -> String {
        let mut hasher = Sha256::new();
        hasher.update(MANIFEST_TOML.as_bytes());
        format!("sha256:{}", hex::encode(hasher.finalize()))
    }

    fn enforce_limits(&self, input: &serde_json::Value) -> FcpResult<()> {{
        if limits::MAX_PAYLOAD_BYTES > 0 && input.to_string().len() > limits::MAX_PAYLOAD_BYTES {{
            return Err(FcpError::InvalidRequest {{
                code: 1006,
                message: "payload exceeds MAX_PAYLOAD_BYTES limit".to_string(),
            }});
        }}
        Ok(())
    }}

    fn scaffold_next_steps() -> Vec<String> {
        vec![
            "Replace scaffold_status with the smallest real provider-backed slice you can verify.".to_string(),
            "Add only the capabilities and network constraints required for that slice.".to_string(),
            "Keep manifest status, runtime truth, and evidence aligned before advertising live support.".to_string(),
        ]
    }

    fn scaffold_status_payload(&self, include_next_steps: bool) -> serde_json::Value {
        let mut payload = json!({
            "connector_id": self.id().as_str(),
            "manifest_status": SURFACE_STATUS,
            "surface_status": SURFACE_STATUS,
            "live_requests_supported": false,
            "implemented_operations": [OP_SCAFFOLD_STATUS],
        });
        if include_next_steps {
            payload
                .as_object_mut()
                .expect("scaffold status payload should be an object")
                .insert("next_steps".into(), json!(Self::scaffold_next_steps()));
        }
        payload
    }

    fn scaffold_status_operation(&self) -> OperationInfo {
        OperationInfo {
            id: OperationId::from_static(OP_SCAFFOLD_STATUS),
            summary: "Inspect scaffold status".to_string(),
            description: Some(
                "Reports the connector's incubating scaffold status and graduation checklist."
                    .to_string(),
            ),
            input_schema: serde_json::json!({
                "type": "object",
                "properties": {
                    "include_next_steps": { "type": "boolean" }
                }
            }),
            output_schema: serde_json::json!({
                "type": "object",
                "properties": {
                    "connector_id": { "type": "string" },
                    "manifest_status": { "type": "string" },
                    "surface_status": { "type": "string" },
                    "live_requests_supported": { "type": "boolean" },
                    "implemented_operations": {
                        "type": "array",
                        "items": { "type": "string" }
                    },
                    "next_steps": {
                        "type": "array",
                        "items": { "type": "string" }
                    }
                },
                "required": [
                    "connector_id",
                    "manifest_status",
                    "surface_status",
                    "live_requests_supported",
                    "implemented_operations"
                ]
            }),
            capability: CapabilityId::from_static(CAP_SCAFFOLD_STATUS),
            risk_level: RiskLevel::Low,
            safety_tier: SafetyTier::Safe,
            idempotency: IdempotencyClass::BestEffort,
            ai_hints: AgentHint {
                when_to_use:
                    "Use this operation to confirm the generated connector is still incubating and non-live."
                        .to_string(),
                common_mistakes: vec![
                    "Treating the scaffold status payload as proof of live upstream support"
                        .to_string(),
                    "Advertising capabilities before the matching provider-backed invoke path exists"
                        .to_string(),
                ],
                examples: Vec::new(),
                related: Vec::new(),
            },
            rate_limit: None,
            requires_approval: Some(ApprovalMode::None),
        }
    }

    /// Run connector diagnostics (V3 doctor endpoint).
    ///
    /// Returns a structured readiness report without leaking secrets.
    pub fn doctor(&self) -> DoctorResult {
        let mut checks = Vec::new();

        // Check 1: Configuration loaded
        let configured = self.config.is_some();
        checks.push(DoctorCheck {
            name: "configuration".into(),
            passed: configured,
            message: Some(if configured {
                "Configuration loaded".into()
            } else {
                "Not configured - run configure first".into()
            }),
            critical: true,
        });

        // Check 2: Runtime initialized
        let runtime_ok = self.runtime.is_some();
        checks.push(DoctorCheck {
            name: "runtime".into(),
            passed: runtime_ok,
            message: Some(if runtime_ok {
                "ConnectorRuntime initialized".into()
            } else {
                "Runtime missing; re-run configure".into()
            }),
            critical: true,
        });

        // Check 3: Capability verifier
        let verifier_ok = self.verifier.is_some();
        checks.push(DoctorCheck {
            name: "capability_verifier".into(),
            passed: verifier_ok,
            message: Some(if verifier_ok {
                "Capability verifier initialized".into()
            } else {
                "Verifier missing; run handshake first".into()
            }),
            critical: false,
        });

        checks.push(DoctorCheck {
            name: "surface_status".into(),
            passed: false,
            message: Some(
                "Connector remains incubating; only the local scaffold_status operation is implemented".into(),
            ),
            critical: false,
        });

        DoctorResult::from_checks(checks)
    }
}

fcp_core::impl_fcp_sealed!(TruthfulPollConnector);

#[async_trait]
impl FcpConnector for TruthfulPollConnector {
    fn id(&self) -> &ConnectorId {
        &self.base.id
    }

    async fn configure(&mut self, config: serde_json::Value) -> FcpResult<()> {
        let config = TruthfulPollConfig::from_value(config)?;
        self.retry_config = config.retry.clone();
        let mut runtime_config = ConnectorRuntimeConfig::from_manifest_str(MANIFEST_TOML)
            .map_err(|error| FcpError::Internal {
                message: format!("Embedded manifest timeout defaults are invalid: {error}"),
            })?;
        if let Some(request_timeout_ms) = config.request_timeout_ms {
            runtime_config =
                runtime_config.with_request_timeout(Duration::from_millis(request_timeout_ms));
        }
        if let Some(runtime) = self.runtime.take() {
            runtime.shutdown();
        }
        self.runtime = Some(ConnectorRuntime::new(runtime_config));
        self.config = Some(config);
        self.verifier = None;
        self.configured = true;
        self.base.set_configured(true);
        self.base.set_handshaken(false);
        Ok(())
    }

    async fn handshake(&mut self, req: HandshakeRequest) -> FcpResult<HandshakeResponse> {
        if !self.configured || self.runtime.is_none() {
            return Err(FcpError::NotConfigured);
        }

        self.base.set_handshaken(true);

        // Initialize capability verifier with host key and zone
        self.verifier = Some(CapabilityVerifier::new(
            req.host_public_key,
            req.zone.clone(),
            self.base.instance_id.clone(),
        ));

        let capabilities_granted = req
            .capabilities_requested
            .into_iter()
            .map(|cap| CapabilityGrant {
                capability: cap,
                operation: None,
            })
            .collect();

        Ok(HandshakeResponse {
            status: "accepted".into(),
            capabilities_granted,
            session_id: SessionId::new(),
            manifest_hash: Self::manifest_hash(),
            nonce: req.nonce,
            event_caps: Some(EventCaps {
                streaming: SUPPORTS_STREAMING,
                replay: false,
                min_buffer_events: 0,
                requires_ack: false,
            }),
            auth_caps: None,
            op_catalog_hash: None,
        })
    }

    async fn health(&self) -> HealthSnapshot {
        let mut snapshot = if self.configured {
            HealthSnapshot::ready()
        } else {
            HealthSnapshot::degraded("not configured")
        };
        snapshot.uptime_ms = self.started_at.elapsed().as_millis() as u64;
        snapshot.details = Some(self.scaffold_status_payload(false));
        snapshot
    }

    async fn self_check(&self) -> FcpResult<SelfCheckReport> {
        if !self.configured {
            return Ok(SelfCheckReport::degraded(
                "not_configured",
                "Connector is not configured",
            ));
        }

        let mut report = SelfCheckReport::degraded(
            "incubating_surface",
            "Connector is configured, but only the local scaffold_status operation is implemented",
        );
        report.details = Some(self.scaffold_status_payload(true));
        Ok(report)
    }

    async fn simulate(&self, req: SimulateRequest) -> FcpResult<SimulateResponse> {
        if req.operation.as_str() != OP_SCAFFOLD_STATUS {
            let error = FcpError::InvalidRequest {
                code: 1004,
                message: format!("Unknown operation: {}", req.operation.as_str()),
            };
            return Ok(SimulateResponse::denied(
                req.id,
                error.to_string(),
                error.error_code(),
            ));
        }

        if !self.configured || self.runtime.is_none() {
            return Ok(SimulateResponse::denied(
                req.id,
                "Connector is not configured",
                FcpError::NotConfigured.error_code(),
            ));
        }

        let Some(verifier) = &self.verifier else {
            return Ok(SimulateResponse::denied(
                req.id,
                "Connector handshake not completed",
                FcpError::NotHandshaken.error_code(),
            ));
        };

        let required_cap = CapabilityId::from_static(CAP_SCAFFOLD_STATUS);
        if let Err(error) = verifier.verify(req.capability_token, &required_cap, &req.operation, &[]) {
            let mut response =
                SimulateResponse::denied(req.id, error.to_string(), error.error_code());
            if error.error_code() == "FCP-3001" {
                response =
                    response.with_missing_capabilities(vec![required_cap.as_str().to_string()]);
            }
            return Ok(response);
        }

        // Default V3 simulate: reflect lifecycle/capability gating without side effects.
        // TODO: Add cost estimation, resource availability checks, etc.
        Ok(SimulateResponse::allowed(req.id))
    }

    fn metrics(&self) -> ConnectorMetrics {
        self.base.metrics()
    }

    async fn shutdown(&mut self, _req: ShutdownRequest) -> FcpResult<()> {
        if let Some(runtime) = self.runtime.take() {
            runtime.shutdown();
        }
        self.config = None;
        self.verifier = None;
        self.configured = false;
        self.base.set_configured(false);
        self.base.set_handshaken(false);
        Ok(())
    }

    fn introspect(&self) -> Introspection {
        Introspection {
            operations: vec![self.scaffold_status_operation()],
            events: Vec::new(),
            resource_types: Vec::new(),
            auth_caps: None,
            event_caps: Some(EventCaps {
                streaming: SUPPORTS_STREAMING,
                replay: false,
                min_buffer_events: 0,
                requires_ack: false,
            }),
        }
    }

    async fn invoke(&self, req: InvokeRequest) -> FcpResult<InvokeResponse> {
        if req.operation.as_str() != OP_SCAFFOLD_STATUS {
            return Err(FcpError::InvalidRequest {
                code: 1004,
                message: format!("Unknown operation: {}", req.operation.as_str()),
            });
        }

        self.base.check_ready()?;
        let verifier = self.verifier.as_ref().ok_or(FcpError::NotHandshaken)?;
        let required_cap = CapabilityId::from_static(CAP_SCAFFOLD_STATUS);
        verifier.verify(req.capability_token, &required_cap, &req.operation, &[])?;
        self.enforce_limits(&req.input)?;
        let runtime = self.runtime.as_ref().ok_or(FcpError::NotConfigured)?;
        let ctx = runtime.request_context();
        let policy = self.retry_config.to_retry_policy();
        let include_next_steps = req
            .input
            .get("include_next_steps")
            .and_then(|value| value.as_bool())
            .unwrap_or(true);
        let output = self.scaffold_status_payload(include_next_steps);

        let output = RetryLoop::execute(&ctx, &policy, |attempt| {
            let output = output.clone();
            async move {
                debug!(
                    attempt,
                    operation = OP_SCAFFOLD_STATUS,
                    surface_status = SURFACE_STATUS,
                    "Executing scaffold-status invoke path"
                );
                AttemptOutcome::Success(output)
            }
        })
        .await
        .map_err(|error: TruthfulPollError| error.to_fcp_error())?;

        Ok(InvokeResponse::ok(req.id, output))
    }

    async fn subscribe(&self, req: SubscribeRequest) -> FcpResult<SubscribeResponse> {
        if !SUPPORTS_STREAMING {
            return Err(FcpError::StreamingNotSupported);
        }


        Ok(SubscribeResponse {
            r#type: "response".into(),
            id: req.id,
            result: SubscribeResult {
                confirmed_topics: req.topics,
                cursors: std::collections::HashMap::new(),
                replay_supported: false,
                buffer: None,
            },
        })
    }

    async fn unsubscribe(&self, _req: UnsubscribeRequest) -> FcpResult<()> {

        Ok(())
    }
}

#[async_trait]
impl Polling for TruthfulPollConnector {
    async fn start_polling(
        &self,
        _target: &str,
        _interval: Option<std::time::Duration>,
        _token: &CapabilityToken,
    ) -> FcpResult<()> {
        if let Ok(mut polling) = self.polling.lock() {
            if !polling.begin_poll() {
                return Err(FcpError::ConnectorUnavailable {
                    code: 5003,
                    message: "poll already in flight".to_string(),
                });
            }
            polling.finish_poll(None);
        }
        Ok(())
    }

    async fn stop_polling(&self, _target: &str, _token: &CapabilityToken) -> FcpResult<()> {
        Ok(())
    }

    async fn poll_now(&self, _target: &str, _token: &CapabilityToken) -> FcpResult<usize> {
        if let Ok(mut polling) = self.polling.lock() {
            if !polling.begin_poll() {
                return Err(FcpError::ConnectorUnavailable {
                    code: 5003,
                    message: "poll already in flight".to_string(),
                });
            }
            // TODO: Execute poll, then update cursor via polling.finish_poll(Some(cursor))
            polling.finish_poll(None);
        }
        Ok(0)
    }

    fn events(&self) -> EventStream {
        crate::polling::empty_event_stream()
    }
}


